mapper.select:
SELECT id ,adjust_log_id ,adjust_batch_no ,flow_node_id ,node_code ,node_label ,node_type ,approval_strategy ,sort_order ,step_status ,handler_id ,handler_name ,process_action ,process_comment ,start_time ,process_time FROM ip_adjust_step
adjust_batch_no = #{adjustBatchNo}
adjust_log_id = #{adjustLogId}
ORDER BY id ASC

SELECT id ,adjust_log_id ,adjust_batch_no ,flow_node_id ,node_code ,node_label ,node_type ,approval_strategy ,sort_order ,step_status ,handler_id ,handler_name ,process_action ,process_comment ,start_time ,process_time FROM ip_adjust_step WHERE flow_node_id = #{flowNodeId} AND handler_id = #{handlerId} AND step_status = 'pending'
AND adjust_batch_no = #{adjustBatchNo}
AND adjust_log_id = #{adjustLogId}
ORDER BY id ASC LIMIT 1

mapper.update:
UPDATE ip_adjust_step
SET step_status = #{stepStatus}
   ,process_action = #{processAction}
   ,process_comment = #{processComment}
   ,process_time = NOW()
   ,updt_time = NOW()
WHERE id = #{id}
  AND step_status = 'pending'

UPDATE ip_adjust_step
SET step_status = #{stepStatus}
   ,process_action = 'skipped'
   ,process_comment = NULL
   ,process_time = NOW()
   ,updt_time = NOW()
WHERE id != #{id}
  AND flow_node_id = #{flowNodeId}
  AND step_status = 'pending'


          AND adjust_batch_no = #{adjustBatchNo}


          AND adjust_log_id = #{adjustLogId}

mapper.select:
SELECT COUNT(1)
FROM ip_adjust_step
WHERE flow_node_id = #{flowNodeId}
  AND step_status = 'pending'


          AND adjust_batch_no = #{adjustBatchNo}


          AND adjust_log_id = #{adjustLogId}

SELECT id ,security_code ,security_short_name ,security_type ,crmw_name ,crmw_scode ,crmw_mktcode ,crmw_stype ,adjust_type ,adjust_mode ,adjust_batch_no ,target_pool_id ,target_pool_name ,pool_type ,flow_id ,flow_key ,flow_type ,audit_status ,adjuster_id ,adjuster_name ,adjust_reason ,adjust_advice ,submit_time ,audit_time ,entry_time FROM ip_adjust_log
is_deleted = 0 AND pool_type = 'crmw'
AND adjust_batch_no = #{adjustBatchNo}
AND id = #{adjustLogId}
ORDER BY id ASC

mapper.update:
UPDATE ip_adjust_log
SET audit_status = #{auditStatus}
   ,audit_time = NOW()
   ,updt_time = NOW()
WHERE is_deleted = 0
  AND pool_type = 'crmw'


          AND adjust_batch_no = #{adjustBatchNo}


          AND id = #{adjustLogId}
